    public void modifyQueryBasedOnDatasourceName(
       Query _inventSum_DS_Query,
       str _inventSum_DS_Name,
       FormDataSource _inventDim_DS)
   {
       Query                   query;
       QueryBuildDataSource    qbdsInventTable;
       QueryBuildDataSource    qbdsInventBatch;
       InventDimParm           lclDimParmVisibleGrid;

       next modifyQueryBasedOnDatasourceName(_inventSum_DS_Query, _inventSum_DS_Name, _inventDim_DS);

       if (!KJP_CM_Utils::checkCurExtIsKKC())
       {
           return;
       }

       query =   _inventSum_DS_Query;

       qbdsInventTable = query.dataSourceTable(tableNum(InventTable));
       if (qbdsInventTable)
       {
           qbdsInventTable.addGroupByField(fieldNum(InventTable, KJPCMSupervisingDepartment));
           qbdsInventTable.addGroupByField(fieldNum(InventTable, PropertyId));
       }

       lclDimParmVisibleGrid = InventDimParm::orParms(dimParmVisibleGrid, lclDimParmVisibleGrid);
       qbdsInventBatch = _inventSum_DS_query.dataSourceTable(tableNum(InventBatch));
       if (lclDimParmVisibleGrid.InventBatchIdFlag == true && qbdsInventBatch)
       {
           qbdsInventBatch.addGroupByField(fieldnum(InventBatch, KJPSMReservationControlFlag));
       }
   }
